;; Inner part: ((({j,p} ∩ {...}) ∪ {f,h,j,k}) ∩ {...}) ∪ {...}) ∪ {a,g,i,n})
(define X1 (I '(j p) '(a c d e g h i k l o p)))  ; {p}
(define X2 (U X1 '(f h j k)))                     ; {f h j k p}
(define X3 (I X2 '(a b c d e f g h i j k l m n o))) ; {f h j k}
(define X4 (U X3 '(b c d g h j l m n o p)))       ; union
(define X5 (U X4 '(a g i n)))
(list X1 X2 X3 X4 X5)

;; The second major conjunct contains ∩ {g,k}, so the whole thing ⊆ {g,k}
